head.script:
// 전역변수
scwin.sDate                     = WebSquare.date.getCurrentServerDate();

scwin.onpageload = function() {
    const codeOptions = [
        { grpCd : "FM040", compID : "gr_adjmContCancel:wrkClsCd" },
    ];
    $c.data.setCommonCode(codeOptions);
};

scwin.onUdcCompleted = function() {
    ica_wrkDt.setValue(scwin.sDate);
    $c.gus.cfDisableKey();
};


//-------------------------------------------------------------------------
// 채권내역 및 수금수단 조회 
//-------------------------------------------------------------------------
// scwin.f_Retrieve = function(condition) {

// };

//-------------------------------------------------------------------------
// 가수금 처리취소시 저장시
//-------------------------------------------------------------------------
scwin.f_Cancel = async function () {

    let checkCount = 0;		// 취소 하고자 하는 Row를 선택했느지 여부
    let cancelCount = 0;	// 수금,가수금선수금(발생)상태를 제외한 전체 갯수
    let cancelRowPosition = 0;		// 취소하고자 하는 Row의 선택위치

    // 처리취소시 필수 조건 Check
    if (! await $c.gus.cfValidate([ica_wrkDt])) {
        return;
    }

    // 처리취소 Row의 선택 위치 확인
    for (i = 0; i < ds_c_adjmContCancel.getRowCount(); i++) {
        if ( ds_c_adjmContCancel.getCellData(i, "num") == "T" ) {
            if ( ds_c_adjmContCancel.getCellData(i, "wrkClsCd") == ACConstants.SUSPINIT_INITAMT_CREATE_PROCESS ){
                await $c.win.alert("상태가 발생인 것은 취소 할수 없습니다. 선택사항을 확인 하시기 바랍니다.");
                return;
            }
            if ( ds_c_adjmContCancel.getCellData(i, "wrkClsCd") == ACConstants.SUSPINIT_BILLRECEIVABL ){
                await $c.win.alert("상태가 수금인 것은 취소 할수 없습니다. 선택사항을 확인 하시기 바랍니다.");
                return;
            }
        }

        // 수금 발생 목록을 제외한 상태의 갯수를 확인
        if ( ds_c_adjmContCancel.getCellData(i, "wrkClsCd") != ACConstants.SUSPINIT_INITAMT_CREATE_PROCESS ||
                ds_c_adjmContCancel.getCellData(i, "wrkClsCd") != ACConstants.SUSPINIT_BILLRECEIVABL ) {
                cancelCount = i;
        }

    }

    for (i = 0; i < ds_c_adjmContCancel.getRowCount(); i++) {
        if (ds_c_adjmContCancel.getCellData(i, "num") == "T" ) {
            checkCount++;
            cancelRowPosition = i;
        }
    }

    // 선택여부 확인
    if ( checkCount <= 0 ) {
        await $c.win.alert("선택하신 사항이 없습니다.");
        return;
    } else if ( checkCount > 1 ) {
        await $c.win.alert("선택사항은 최근 발생항목 한개만 선택 하셔야 합니다.");
    }

    // 마지막 상태만 취소처리가 가능함.
    if ( cancelCount != cancelRowPosition ) {
        await $c.win.alert("처리취소는 마지막 부터 가능합니다.");
        return;
    }


    // 처리 취소여부 확인
    if (await $c.win.confirm(MSG_CM_CRM_001)) {
        for (i = 0; i < ds_c_adjmContCancel.getRowCount(); i++) {
            if ( ds_c_adjmContCancel.getCellData(i, "num") == "T" ) {
                ds_c_adjmContCancel.setCellData(i, "iwrkDt", ica_wrkDt.getValue());
                ds_c_adjmContCancel.setCellData(i, "acctCd", ACConstants.ACCTCD_SUS_RECV);
            }
        }	
        // 선수금처리 취소
        if ( ds_c_adjmContCancel.getCellData(ds_c_adjmContCancel.getModifiedIndex()[0], "wrkClsCd") == ACConstants.SUSPINIT_INITAMT_PROCESS) {
            sbm_adjmContCancel.action = "/ac.fm.collmoneymgnt.rcptmgnt.CancelInitiativeAmountProcessCMD.do";
        // 환불처리 취소
        } else if ( ds_c_adjmContCancel.getCellData(ds_c_adjmContCancel.getModifiedIndex()[0], "wrkClsCd") == ACConstants.SUSPINIT_REFUND_PROCESS){
            sbm_adjmContCancel.action = "/ac.fm.collmoneymgnt.rcptmgnt.CancelReturnProcessCMD.do";
        // 잡이익 처리 취소
        } else if ( ds_c_adjmContCancel.getCellData(ds_c_adjmContCancel.getModifiedIndex()[0], "wrkClsCd") == ACConstants.SUSPINIT_PROFIT_PROCESS){
            sbm_adjmContCancel.action = "/ac.fm.collmoneymgnt.rcptmgnt.CancelEtcgainsProcessCMD.do";
        // 선수금역분개 처리 취소
        } else if ( ds_c_adjmContCancel.getCellData(ds_c_adjmContCancel.getModifiedIndex()[0], "wrkClsCd") == ACConstants.SUSPINIT_INITAMT_CANCEL){
            sbm_adjmContCancel.action = "/ac.fm.collmoneymgnt.rcptmgnt.CancelInitiativeAmountReverseCMD.do";
        // 환불처리 역분개 처리 취소
        } else if ( ds_c_adjmContCancel.getCellData(ds_c_adjmContCancel.getModifiedIndex()[0], "wrkClsCd") == ACConstants.SUSPINIT_REFUND_CANCEL){
            sbm_adjmContCancel.action = "/ac.fm.collmoneymgnt.rcptmgnt.CancelReturnReverseCMD.do";
        // 잡이익 역분개 처리 취소
        } else if ( ds_c_adjmContCancel.getCellData(ds_c_adjmContCancel.getModifiedIndex()[0], "wrkClsCd") == ACConstants.SUSPINIT_PROFIT_CANCEL){
            sbm_adjmContCancel.action = "/ac.fm.collmoneymgnt.rcptmgnt.CancelEtcgainsReverseCMD.do";
        // 반제 처리 취소
        } else if ( ds_c_adjmContCancel.getCellData(ds_c_adjmContCancel.getModifiedIndex()[0], "wrkClsCd") == ACConstants.SUSPINIT_REPAYMENT_PROCESS){
            sbm_adjmContCancel.action = "/ac.fm.collmoneymgnt.rcptmgnt.CancelSuspenseReceivableRepaymentProcessCMD.do";
        // 반제 역분개 처리취소
        } else if ( ds_c_adjmContCancel.getCellData(ds_c_adjmContCancel.getModifiedIndex()[0], "wrkClsCd") == ACConstants.SUSPINIT_REPAYMENT_CANCEL){
            sbm_adjmContCancel.action = "/ac.fm.collmoneymgnt.rcptmgnt.CancelSuspenseReceivableRepaymentReverseCMD.do";
        } else {
            await $c.win.alert("취소 처리 할수 없는 상태입니다.\n가수금 정산내역이 생성된 메뉴에서 취소처리 하시기 바랍니다");
            return;
        }

        $c.sbm.execute(sbm_adjmContCancel);


        // 저장 완료후 Parent 화면의 조회 결과 재조회 한다.
        $p.parent().scwin.f_Retrieve();

        $p.parent().tabControl1.getWindow(1).$p.getComponentById("ed_amt").setValue(0);

    }
}


//-------------------------------------------------------------------------
// 엑셀 파일 다운로드
//-------------------------------------------------------------------------
scwin.f_Excel = async function () {
    if (ds_c_adjmContCancel.getRowCount() == 0) {
        await $c.win.alert(MSG_CM_WRN_002);
        return;
    }

    let infoArr = [{
        rowIndex : 0,             // 첫 번째 줄
        colIndex : 0,             // 첫 번째 칸부터
        colSpan : 13,   // 그리드 전체 너비만큼 병합
        rowSpan : 1,
        text : "정산내역/처리취소",
        textAlign : "center",     //정렬
        fontSize : 18,
        drawBorder : false,        // 테두리
        color : "black",          // 글자색
        backgroundColor : "white" // 배경색
    }]

    const options = {
        fileName: "정산내역_처리취소.xlsx",
        sheetName: "정산내역_처리취소",
        startRowIndex : 2,
        startColumnIndex : 0,
        type : 1
    };

    if (await $c.win.confirm("Excel로 다운로드 하시겠습니까?")) {
        $c.data.downloadGridViewExcel(gr_adjmContCancel, options, infoArr);
    }
};

//-------------------------------------------------------------------------
// script
//-------------------------------------------------------------------------
// grid decode format
scwin.susRecvInitamtSeqDisplayFm = function(data) {
    return $c.gus.decode(data, "0", "", data);
}

scwin.sbm_adjmContCancel_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) {
        $p.parent().scwin.f_Retrieve();
        return;
    }
    await $c.gus.cfAlertMsg(MSG_CM_INF_001);
    $p.parent().scwin.f_Retrieve();
};


scwin.gr_adjmContCancel_oncellclick = async function (rowIndex, columnIndex, columnId) {
    if ( columnId == "slipNo" ) { 
        var slipNo = ds_c_adjmContCancel.getCellData(rowIndex, "slipNo");
        if ( slipNo !=  "" ) {
            let rtnList = await $c.gus.cfShowSlipInfo( slipNo );
        } 
    }  
};
